class Solution(object):
    def maxTotalReward(self, rewardValues):
        """
        :type rewardValues: List[int]
        :rtype: int
        """
        rewardValues = sorted(set(rewardValues))
        n = len(rewardValues)

        # dp[i] represents reachable total rewards using first i distinct rewards
        # Use a set to store reachable values
        reachable = {0}

        for reward in rewardValues:
            # New reachable values after considering this reward
            new_reachable = set(reachable)
            for current_sum in reachable:
                # Can take this reward if current_sum < reward
                if current_sum < reward:
                    new_reachable.add(current_sum + reward)
            reachable = new_reachable

        return max(reachable)
